#include<bits/stdc++.h>
using namespace std;
bool f;
long long a,b,n;
char c;
string s[100],s2;
void sb(char c,int a,int b,int i) {
	long long f=0,sum=0,d=0;
	cout<<a;
	if(c=='a') {
		cout<<'+';
	} else {
		if(c=='b') {
			cout<<'-';
		} else {
			cout<<'*';
		}
	}
	cout<<b<<'=';
	if(c=='a') {
		d=a+b;
		cout<<d<<'\n';
	} else {
		if(c=='b') {
			d=a-b;
			if(d<0)f=1;
			cout<<d<<'\n';
			d=abs(d);
		} else {
			d=a*b;
			cout<<d<<'\n';
		}
	}
	if(a==0)sum++;
	if(b==0)sum++;
	if(d==0)sum++;
	while(a>0) {
		sum++;
		a/=10;
	}
	while(b>0) {
		sum++;
		b/=10;
	}
	while(d>0) {
		sum++;
		d/=10;
	}
	cout<<sum+2+f;
	if(i!=n)cout<<'\n';
}
int main() {
	cin>>n;
	getchar();
	for(int i=1; i<=n; i++) {
		getline(cin,s[i]);
//		getchar();
	}
	for(int i=1; i<=n; i++) {
		int k=0;
		if(isalpha(s[i][0])) {
			c=s[i][0];
			k=2;
		}
		a=b=f=0;
		for(int j=k; j<s[i].size(); j++) {
			
			if(s[i][j]>='0' && s[i][j]<='9' && f==0) {
				a*=10;
				a+=s[i][j]-'0';
			} else {
				if(s[i][j]>='0' && s[i][j]<='9' && f==1) {
					b*=10;
					b+=s[i][j]-'0';
				}
			}
			if(s[i][j]==' ') {
				f=1;
				continue;
			}
		}
		sb(c,a,b,i);
	}
	return 0;
}
